DROP TABLE IF EXISTS `student_answer`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_answer` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `submission_id` bigint DEFAULT NULL,
  `student_id` bigint NOT NULL COMMENT '学生ID',
  `assignment_id` bigint NOT NULL COMMENT '作业ID',
  `question_id` bigint NOT NULL COMMENT '题目ID',
  `answer` text COMMENT '学生答案（文本）',
  `answer_content` longtext COMMENT '富文本答案（主观题）',
  `score` int DEFAULT NULL COMMENT '本题得分',
  `ai_score` int DEFAULT NULL COMMENT 'AI评分',
  `final_score` int DEFAULT NULL COMMENT '最终得分（教师复核后）',
  `ai_feedback` text COMMENT 'AI生成的反馈（JSON格式，包含错误点、建议等）',
  `teacher_feedback` text COMMENT '教师评语',
  `feedback` text COMMENT '合并后的反馈（展示用）',
  `grader_type` varchar(20) DEFAULT 'AI' COMMENT '批改类型：AI/TEACHER',
  `review_status` int DEFAULT '0' COMMENT '复核状态：0-无需复核,1-待复核,2-已复核',
  `reviewer_id` bigint DEFAULT NULL COMMENT '复核人ID',
  `review_time` datetime DEFAULT NULL COMMENT '复核时间',
  `is_draft` tinyint DEFAULT '0' COMMENT '是否为草稿（0-正式提交,1-自动保存草稿）',
  `status` int DEFAULT '1' COMMENT '状态：1-有效,0-无效',
  `submit_time` datetime DEFAULT NULL COMMENT '提交时间（正式提交时记录）',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `version` int DEFAULT '1' COMMENT '乐观锁版本号',
  PRIMARY KEY (`id`),
  KEY `idx_submission_id` (`submission_id`),
  KEY `idx_student_id` (`student_id`),
  KEY `idx_assignment_id` (`assignment_id`),
  KEY `idx_question_id` (`question_id`),
  KEY `idx_review_status` (`review_status`),
  KEY `idx_is_draft` (`is_draft`),
  KEY `fk_sa_reviewer` (`reviewer_id`),
  CONSTRAINT `fk_sa_assignment` FOREIGN KEY (`assignment_id`) REFERENCES `assignment` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_sa_question` FOREIGN KEY (`question_id`) REFERENCES `question` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_sa_reviewer` FOREIGN KEY (`reviewer_id`) REFERENCES `user` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_sa_student` FOREIGN KEY (`student_id`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_sa_submission` FOREIGN KEY (`submission_id`) REFERENCES `submission` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=97 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
